mapper.select:
SELECT id, mission_id, assignee_id, assigned_by, family_id, due_date, status, points, created_at, updated_at
FROM mission_assignments
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

SELECT id, mission_id, assignee_id, assigned_by, family_id, due_date, status, points, created_at, updated_at
FROM mission_assignments
WHERE family_id = #{familyId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND assignee_id = #{assigneeId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
ORDER BY updated_at DESC, created_at DESC

SELECT id, mission_id, assignee_id, assigned_by, family_id, due_date, status, points, created_at, updated_at
FROM mission_assignments
WHERE assignee_id = #{assigneeId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND status = #{status, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.MissionStatusTypeHandler}
ORDER BY created_at DESC

mapper.update:
UPDATE mission_assignments
SET status = #{status, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.MissionStatusTypeHandler},
    points = #{points},
    due_date = #{dueDate},
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

mapper.select:
SELECT COUNT(1)
FROM mission_assignments
WHERE mission_id = #{missionId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND assignee_id = #{assigneeId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND due_date = #{dueDate}
  AND status IN ('todo', 'pending', 'approved', 'rejected')

SELECT COUNT(1)
FROM mission_assignments
WHERE mission_id = #{missionId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND assignee_id = #{assigneeId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND due_date BETWEEN #{startDate} AND #{endDate}
  AND status IN ('todo', 'pending', 'approved', 'rejected')
